-- ═══════════════════════════════════════════════════════════════
-- Migración 113: Catálogo de coberturas y subcoberturas
--
-- Tablas:
--   coverage_catalog: coberturas principales (nivel 1 = POL)
--   subcoverage_catalog: subcoberturas/cláusulas (nivel 2 = CAD)
--
-- Datos importados desde SQL Server (TIPO_COBERTURAS)
-- Total: 2019 coberturas, 2346 subcoberturas
-- ═══════════════════════════════════════════════════════════════

-- 1. Tabla coverage_catalog
CREATE TABLE IF NOT EXISTS coverage_catalog (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  legacy_id bigint,
  code text NOT NULL,
  name text NOT NULL,
  description text,
  theme text NOT NULL DEFAULT 'Otro',
  is_active boolean NOT NULL DEFAULT true,
  sort_order integer NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_coverage_catalog_code ON coverage_catalog(code);
CREATE INDEX IF NOT EXISTS idx_coverage_catalog_theme ON coverage_catalog(theme);
CREATE INDEX IF NOT EXISTS idx_coverage_catalog_active ON coverage_catalog(is_active);
CREATE INDEX IF NOT EXISTS idx_coverage_catalog_name ON coverage_catalog(name);

-- 2. Tabla subcoverage_catalog
CREATE TABLE IF NOT EXISTS subcoverage_catalog (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  coverage_catalog_id uuid REFERENCES coverage_catalog(id) ON DELETE CASCADE,
  legacy_id bigint,
  code text NOT NULL,
  name text NOT NULL,
  description text,
  is_active boolean NOT NULL DEFAULT true,
  sort_order integer NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_subcoverage_catalog_parent ON subcoverage_catalog(coverage_catalog_id);
CREATE UNIQUE INDEX IF NOT EXISTS idx_subcoverage_catalog_code ON subcoverage_catalog(code);
CREATE INDEX IF NOT EXISTS idx_subcoverage_catalog_active ON subcoverage_catalog(is_active);

-- 3. Triggers de updated_at
CREATE OR REPLACE FUNCTION trg_coverage_catalog_updated_at()
RETURNS trigger AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS coverage_catalog_updated_at ON coverage_catalog;
CREATE TRIGGER coverage_catalog_updated_at
  BEFORE UPDATE ON coverage_catalog
  FOR EACH ROW EXECUTE FUNCTION trg_coverage_catalog_updated_at();

DROP TRIGGER IF EXISTS subcoverage_catalog_updated_at ON subcoverage_catalog;
CREATE TRIGGER subcoverage_catalog_updated_at
  BEFORE UPDATE ON subcoverage_catalog
  FOR EACH ROW EXECUTE FUNCTION trg_coverage_catalog_updated_at();

-- 4. RLS
ALTER TABLE coverage_catalog ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "coverage_catalog_all" ON coverage_catalog;
CREATE POLICY "coverage_catalog_all" ON coverage_catalog
  FOR ALL USING (true) WITH CHECK (true);

ALTER TABLE subcoverage_catalog ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "subcoverage_catalog_all" ON subcoverage_catalog;
CREATE POLICY "subcoverage_catalog_all" ON subcoverage_catalog
  FOR ALL USING (true) WITH CHECK (true);

