-- 7. Agregar FKs a policy_coverages para referenciar el catálogo
ALTER TABLE policy_coverages ADD COLUMN IF NOT EXISTS coverage_catalog_id uuid REFERENCES coverage_catalog(id) ON DELETE SET NULL;
ALTER TABLE policy_coverages ADD COLUMN IF NOT EXISTS subcoverage_catalog_id uuid REFERENCES subcoverage_catalog(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_policy_coverages_catalog ON policy_coverages(coverage_catalog_id);
CREATE INDEX IF NOT EXISTS idx_policy_coverages_subcatalog ON policy_coverages(subcoverage_catalog_id);

